     1→import Link from 'next/link';
     2→
     3→interface TagProps {
     4→  tag: string;
     5→  count?: number;
     6→  variant?: 'default' | 'compact' | 'large';
     7→  showHash?: boolean;
     8→}
     9→
    10→/**
    11→ * Unified tag component for consistent styling across the site.
    12→ * Variants:
    13→ * - default: Standard pill-style tag (for post headers)
    14→ * - compact: Minimal inline style (for post lists)
    15→ * - large: Card-style with optional count (for tag cloud)
    16→ */
    17→export default function Tag({ tag, count, variant = 'default', showHash = true }: TagProps) {
    18→  const baseClasses = 'no-underline transition-colors duration-200 focus:outline-none focus:ring-2 focus:ring-accent/50';
    19→
    20→  const variantClasses = {
    21→    default: 'inline-flex px-3 py-1 bg-muted/10 rounded-full text-xs font-medium text-muted hover:bg-accent/10 hover:text-accent',
    22→    compact: 'text-xs text-muted hover:text-accent',
    23→    large: 'group relative inline-flex items-center px-4 py-2 rounded-xl border border-muted/20 bg-muted/5 hover:bg-background hover:border-accent hover:shadow-md hover:shadow-accent/5',
    24→  };
    25→
    26→  return (
    27→    <Link
    28→      href={`/tags/${tag.toLowerCase()}`}
    29→      className={`${baseClasses} ${variantClasses[variant]}`}
