    25→function getVisibleIndices(total: number, current: number): (number | 'ellipsis')[] {
    26→  if (total <= 7) return Array.from({ length: total }, (_, i) => i);
    27→  const result: (number | 'ellipsis')[] = [];
    28→  result.push(0);
    29→  const windowStart = Math.max(1, current - 2);
    30→  const windowEnd = Math.min(total - 2, current + 2);
    31→  if (windowStart > 1) result.push('ellipsis');
    32→  for (let i = windowStart; i <= windowEnd; i++) result.push(i);
    33→  if (windowEnd < total - 2) result.push('ellipsis');
    34→  result.push(total - 1);
    35→  return result;
    36→}
