    '---',
    `title: "${escapedTitle}"`,
    `date: "${date}"`,
    `tags: ${tagsLiteral(tags)}`,
    `aliases: ${tagsLiteral(aliases)}`,
    '---',
    '',
    body,
    '',
  ].join('\n');

