const args = process.argv.slice(2);

const vaultIdx   = args.indexOf('--vault');
const vaultArg   = vaultIdx > -1 ? args[vaultIdx + 1] : null;

const positional   = args.filter((a, i) => !a.startsWith('--') && args[i - 1] !== '--vault');
